clear 
syms x y
syms f(x,y)
f(x,y) = 5*x^2 - 6*x*y + 5*y^2 %[output:16012bb5]

% Define the function for optimization
F = matlabFunction(f);
[X, Y] = meshgrid(linspace(-1.5, 1.5, 100));
contour(X, Y, F(X, Y), "w"); %[output:94cf9941]
hold on %[output:94cf9941]

p = [-1 -1];
[min, count] = successive_descent(f, p, 0.1, 2) %[output:12094d0a] %[output:1f471f46] %[output:0d24b7dc] %[output:94cf9941]
hold off; %[output:94cf9941]

function [p, count] = successive_descent(f, p, tol, step_size, dstep)
arguments
    f % The function
    p % initial guess
    tol = 0.01 % tolerance
    step_size = 10 % big step size that will go over the minimum
    dstep = 0.0001 % small step size to test direction
end
F = matlabFunction(f);
args = argnames(f);
syms lambda
syms g(lambda)
N = length(args);
i = eye(N);
gap = tol+1;
count = 0;
while gap > tol && count < 20
    old_p = p;
    for n=1:N
        % gives a nx1 matrix of args to pass to the function
        % looks like
        g_args = (lambda * i(:, n))+p';
        C = num2cell(g_args);
        g(lambda) = f(C{:});
        G = matlabFunction(g);
        % this get's the nth parameter from p which will be our initial guess
        l = p(n);
        direction = 1;
        if G(l) < G(l + dstep)
            % if we take a small step and it is smaller we're going the
            % wrong way
            direction = -1;
        end
        step = step_size * direction;
        lstep = l + step;
        next = modgss(G, l, lstep, F(p(1), p(2)), n, 0.001, 1000);
        this_p = p;
        p(n) = next;
        dp = p - this_p;
        fprintf("%d: %.2f %.2f\n", n, this_p(1), this_p(2));
        quiver(this_p(1), this_p(2), dp(1), dp(2))
    end
    gap = max(abs(p - old_p));
    count = count + 1;
end
end
